import React, { useState, useRef, useEffect } from 'react';

function format(ms) {
  const pad = (n) => String(n).padStart(2, '0');
  const cs = Math.floor((ms % 1000) / 10);
  const s = Math.floor(ms / 1000) % 60;
  const m = Math.floor(ms / 60000);
  return `${pad(m)}:${pad(s)}.${pad(cs)}`;
}

export default function Stopwatch() {
  const [elapsed, setElapsed] = useState(0);
  const [running, setRunning] = useState(false);
  const [laps, setLaps] = useState([]);
  const startRef = useRef(0);
  const rafRef = useRef(null);

  const tick = () => {
    setElapsed(Date.now() - startRef.current);
    rafRef.current = requestAnimationFrame(tick);
  };

  const start = () => {
    if (running) return;
    startRef.current = Date.now() - elapsed;
    setRunning(true);
    rafRef.current = requestAnimationFrame(tick);
  };

  const stop = () => {
    setRunning(false);
    cancelAnimationFrame(rafRef.current);
  };

  const reset = () => {
    stop();
    setElapsed(0);
    setLaps([]);
  };

  const lap = () => setLaps((prev) => [...prev, elapsed]);

  useEffect(() => () => cancelAnimationFrame(rafRef.current), []);

  const btn = {
    padding: '8px 16px',
    fontSize: 15,
    cursor: 'pointer',
    border: '1px solid #ccc',
    borderRadius: 6,
    background: '#f7f7f7',
  };

  return (
    <div>
      <div style={{ fontSize: 44, fontVariantNumeric: 'tabular-nums', fontWeight: 700 }}>
        {format(elapsed)}
      </div>
      <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
        {!running ? (
          <button style={btn} onClick={start}>Start</button>
        ) : (
          <button style={btn} onClick={stop}>Stop</button>
        )}
        <button style={btn} onClick={lap} disabled={!running}>Lap</button>
        <button style={btn} onClick={reset}>Reset</button>
      </div>
      {laps.length > 0 && (
        <ol style={{ marginTop: 16, lineHeight: 1.6 }}>
          {laps.map((l, i) => (
            <li key={i} style={{ fontVariantNumeric: 'tabular-nums' }}>{format(l)}</li>
          ))}
        </ol>
      )}
    </div>
  );
}

