import { Component, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-stopwatch',
  template: `
    <div>
      <div style="font-size: 44px; font-weight: 700; font-variant-numeric: tabular-nums;">{{ format(elapsed) }}</div>
      <div style="display: flex; gap: 8px; margin-top: 12px;">
        <button *ngIf="!running" (click)="start()" style="padding: 8px 16px; font-size: 15px; cursor: pointer; border: 1px solid #ccc; border-radius: 6px; background: #f7f7f7;">Start</button>
        <button *ngIf="running" (click)="stop()" style="padding: 8px 16px; font-size: 15px; cursor: pointer; border: 1px solid #ccc; border-radius: 6px; background: #f7f7f7;">Stop</button>
        <button (click)="lap()" [disabled]="!running" style="padding: 8px 16px; font-size: 15px; cursor: pointer; border: 1px solid #ccc; border-radius: 6px; background: #f7f7f7;">Lap</button>
        <button (click)="reset()" style="padding: 8px 16px; font-size: 15px; cursor: pointer; border: 1px solid #ccc; border-radius: 6px; background: #f7f7f7;">Reset</button>
      </div>
      <ol *ngIf="laps.length" style="margin-top: 16px; line-height: 1.6; font-variant-numeric: tabular-nums;">
        <li *ngFor="let l of laps">{{ format(l) }}</li>
      </ol>
    </div>
  `,
})
export class StopwatchComponent implements OnDestroy {
  elapsed = 0;
  running = false;
  laps: number[] = [];
  private startTime = 0;
  private handle: any = null;

  format(ms: number): string {
    const pad = (n: number) => String(n).padStart(2, '0');
    const cs = Math.floor((ms % 1000) / 10);
    const s = Math.floor(ms / 1000) % 60;
    const m = Math.floor(ms / 60000);
    return pad(m) + ':' + pad(s) + '.' + pad(cs);
  }

  start(): void {
    if (this.running) {
      return;
    }
    this.startTime = Date.now() - this.elapsed;
    this.running = true;
    this.handle = setInterval(() => {
      this.elapsed = Date.now() - this.startTime;
    }, 30);
  }

  stop(): void {
    this.running = false;
    clearInterval(this.handle);
  }

  reset(): void {
    this.stop();
    this.elapsed = 0;
    this.laps = [];
  }

  lap(): void {
    this.laps.push(this.elapsed);
  }

  ngOnDestroy(): void {
    clearInterval(this.handle);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Stopwatch Demo</h1>
      <app-stopwatch></app-stopwatch>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, StopwatchComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
